class TestListSessions:
    def test_empty(self, client) -> None:
        resp = client.get("/api/v1/sessions")
        assert resp.status_code == 200
        assert resp.json() == []

    def test_returns_sessions(self, client, db) -> None:
        run_async(_seed_session(db, session_id="s1"))
        resp = client.get("/api/v1/sessions")
        data = resp.json()
        assert len(data) == 1
        assert data[0]["session_id"] == "s1"
        assert data[0]["platform"] == "claude"
        assert data[0]["derived_state"] == "working"

    def test_active_filter(self, client, db) -> None:
        run_async(_seed_session(db, session_id="alive"))
        run_async(_seed_session(db, session_id="dead"))
        run_async(
            schema.update_session_pid_alive(db, session_id="dead", pid_alive=False)
        )

        resp = client.get("/api/v1/sessions?active=true")
        data = resp.json()
        assert len(data) == 1
        assert data[0]["session_id"] == "alive"


