class TestClearSession:
    def test_clears_state(self, client, db) -> None:
        run_async(
            _seed_session(
                db, session_id="s1", last_event="PreToolUse", last_tool="Bash"
            )
        )
        run_async(
            schema.upsert_agent(
                db,
                agent_id="a1",
                session_id="s1",
                agent_type="Explore",
                last_event="PreToolUse",
            )
        )

        resp = client.post("/api/v1/sessions/s1/clear")
        assert resp.status_code == 200
        assert resp.json()["status"] == "cleared"

        # Session state should be wiped
        row = run_async(schema.get_session(db, session_id="s1"))
        assert row["last_event"] is None
        assert row["last_tool"] is None
        assert row["last_event_at"] is None

        # Agent should be ended
        agents = run_async(schema.get_session_agents(db, session_id="s1"))
        assert agents[0]["ended_at"] is not None

        # A clear_state event should exist
        events = run_async(schema.get_session_events(db, session_id="s1"))
        assert any(e["event_name"] == "clear_state" for e in events)

    def test_not_found(self, client) -> None:
        resp = client.post("/api/v1/sessions/nonexistent/clear")
        assert resp.status_code == 404


