    def test_hook_sets_source_system(self, client, db) -> None:
        client.post(
            "/hooks/claude",
            json={
                "session_id": "s1",
                "hook_event_name": "PreToolUse",
                "tool_name": "Bash",
                "source_system": "remote-vm",
            },
        )
        row = run_async(schema.get_session(db, session_id="s1"))
        assert row["source_system"] == "remote-vm"
